// ── Shared attr shapes ────────────────────────────────────────────────

type Empty = Record<string, never>;

export interface BlockAttrs {
  backgroundColor?: string;
  textColor?: string;
  fontSize?: string;
  fontFamily?: string;
  textAlign?: "left" | "center" | "right" | "justify";
}

interface CellAttrs {
  backgroundColor?: string;
  colspan?: number;
  rowspan?: number;
  colwidth?: number[] | null;
}

// ── Marks ─────────────────────────────────────────────────────────────

export interface MarkDefs {
  bold: { attrs?: Empty };
  italic: { attrs?: Empty };
  strike: { attrs?: Empty };
  code: { attrs?: Empty };
  underline: { attrs?: Empty };
  link: { attrs: { href: string; target: string } };
  textStyle: {
    attrs?: {
      color: string | null;
      fontFamily: string | null;
      fontSize: string | null;
    };
  };
}

export type AnyMark = {
  [T in keyof MarkDefs]: { type: T } & MarkDefs[T];
}[keyof MarkDefs];

// ── Inline nodes ──────────────────────────────────────────────────────

export type TextNode = { type: "text"; text: string; marks?: AnyMark[] };
export type HardBreakNode = { type: "hardBreak" };
export type EmojiNode = {
  type: "emoji";
  attrs: {
    name: string;
    hexId: string;
  };
};
export type InlineNode = TextNode | HardBreakNode | EmojiNode;

// ── Block nodes ───────────────────────────────────────────────────────

export type ParagraphNode = {
  type: "paragraph";
  attrs?: BlockAttrs;
  content?: InlineNode[];
};
export type HeadingNode = {
  type: "heading";
  attrs: BlockAttrs & { level: 1 | 2 | 3 };
  content?: InlineNode[];
};
export type BlockquoteNode = {
  type: "blockquote";
  attrs?: BlockAttrs;
  content?: BlockNode[];
};
export type CodeBlockNode = {
  type: "codeBlock";
  attrs: { language: string };
  content?: TextNode[];
};
export type HorizontalRule = { type: "horizontalRule" };
export type ImageNode = {
  type: "image";
  attrs: {
    src: string | null;
    caption?: string;
    align: "left" | "center" | "full" | "right";
    width?: number | undefined;
    height?: number | undefined;
  };
};
export type CalloutNode = {
  type: "callout";
  attrs: BlockAttrs & { emoji: string };
  content?: BlockNode[];
};

// ── List nodes ────────────────────────────────────────────────────────

export type ListItemNode = { type: "listItem"; content?: BlockNode[] };
export type TaskItemNode = {
  type: "taskItem";
  attrs: { checked: boolean };
  content?: BlockNode[];
};
export type BulletListNode = { type: "bulletList"; content?: ListItemNode[] };
export type OrderedListNode = {
  type: "orderedList";
  attrs: { start: number; type: string | null };
  content?: ListItemNode[];
};
export type TaskListNode = { type: "taskList"; content?: TaskItemNode[] };

// ── Table nodes ───────────────────────────────────────────────────────

export type TableCellNode = {
  type: "tableCell";
  attrs?: CellAttrs;
  content?: BlockNode[];
};
export type TableHeaderNode = {
  type: "tableHeader";
  attrs?: CellAttrs;
  content?: BlockNode[];
};
export type TableRowNode = {
  type: "tableRow";
  content?: (TableCellNode | TableHeaderNode)[];
};
export type TableNode = { type: "table"; content?: TableRowNode[] };

// ── Unions ────────────────────────────────────────────────────────────

export type BlockNode =
  | ParagraphNode
  | HeadingNode
  | BlockquoteNode
  | CodeBlockNode
  | HorizontalRule
  | ImageNode
  | CalloutNode
  | BulletListNode
  | OrderedListNode
  | TaskListNode
  | TableNode;

export type AnyEditorNode =
  | BlockNode
  | InlineNode
  | ListItemNode
  | TaskItemNode
  | TableRowNode
  | TableCellNode
  | TableHeaderNode;

// ── Root ──────────────────────────────────────────────────────────────

export type DocContent = { type: "doc"; content: BlockNode[] };

export { docToReact } from "./react";
export { docToHTML } from "./html";
export { docToMarkdown } from "./markdown";

const CDN = {
  twemoji: "https://cdn.jsdelivr.net/gh/jdecked/twemoji@latest/assets",
  notoAnimated: "https://fonts.gstatic.com/s/e/notoemoji/latest",
} as const;

export const getEmojiUrl = (
  hexId: string,
  source: "inline" | "callout-icon",
): string => {
  const lower = hexId.toLowerCase();
  const underscored = lower.replace(/-/g, "_");

  switch (source) {
    case "inline":
      return `${CDN.twemoji}/svg/${lower}.svg`;

    case "callout-icon":
      return `${CDN.notoAnimated}/${underscored}/512.webp`;
  }
};

import type {
  DocContent,
  BlockNode,
  InlineNode,
  AnyMark,
  ParagraphNode,
  HeadingNode,
  BlockquoteNode,
  CodeBlockNode,
  ImageNode,
  CalloutNode,
  BulletListNode,
  OrderedListNode,
  TaskListNode,
  ListItemNode,
  TaskItemNode,
  TableNode,
  TableRowNode,
  TableCellNode,
  TableHeaderNode,
  BlockAttrs,
} from "../jsonContent";
import { getEmojiUrl } from "./utils";

// ── Escapers ──────────────────────────────────────────────────────────

function escapeText(s: string): string {
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

function escapeAttr(s: string): string {
  return s
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

// ── Attribute / style emitters ────────────────────────────────────────

function attr(name: string, value: string | number | undefined | null): string {
  if (value === undefined || value === null || value === "") return "";
  return ` ${name}="${escapeAttr(String(value))}"`;
}

function styleAttr(css: string | undefined): string {
  return css ? ` style="${escapeAttr(css)}"` : "";
}

function blockAttrsToStyle(attrs?: BlockAttrs): string | undefined {
  if (!attrs) return undefined;
  const parts: string[] = [];
  if (attrs.backgroundColor)
    parts.push(`background-color: ${attrs.backgroundColor}`);
  if (attrs.textColor) parts.push(`color: ${attrs.textColor}`);
  if (attrs.fontSize) parts.push(`font-size: ${attrs.fontSize}`);
  if (attrs.fontFamily) parts.push(`font-family: ${attrs.fontFamily}`);
  if (attrs.textAlign) parts.push(`text-align: ${attrs.textAlign}`);
  return parts.length ? parts.join("; ") : undefined;
}

// ── Mark wrapping ─────────────────────────────────────────────────────

function wrapMark(content: string, mark: AnyMark): string {
  switch (mark.type) {
    case "bold":
      return `<strong>${content}</strong>`;
    case "italic":
      return `<em>${content}</em>`;
    case "strike":
      return `<s>${content}</s>`;
    case "underline":
      return `<u>${content}</u>`;
    case "code":
      return `<code>${content}</code>`;
    case "link":
      return `<a${attr("href", mark.attrs.href)}${attr("target", mark.attrs.target)} rel="noreferrer">${content}</a>`;
    case "textStyle": {
      const parts: string[] = [];
      if (mark.attrs?.color) parts.push(`color: ${mark.attrs.color}`);
      if (mark.attrs?.fontFamily)
        parts.push(`font-family: ${mark.attrs.fontFamily}`);
      if (mark.attrs?.fontSize) parts.push(`font-size: ${mark.attrs.fontSize}`);
      const style = parts.length ? parts.join("; ") : undefined;
      return `<span${styleAttr(style)}>${content}</span>`;
    }
  }
}

function applyMarks(content: string, marks: AnyMark[] | undefined): string {
  if (!marks || marks.length === 0) return content;
  return marks.reduce<string>((node, mark) => wrapMark(node, mark), content);
}

// ── Inline rendering ──────────────────────────────────────────────────

function renderInline(node: InlineNode): string {
  switch (node.type) {
    case "text":
      return applyMarks(escapeText(node.text), node.marks);
    case "hardBreak":
      return "<br>";
    case "emoji":
      return `<span data-type="emoji"><img${attr(
        "src",
        getEmojiUrl(node.attrs.hexId, "inline"),
      )}${attr("alt", node.attrs.name)}></span>`;
  }
}

function renderInlineContent(nodes?: InlineNode[]): string {
  return (nodes ?? []).map(renderInline).join("");
}

// ── Block renderers ───────────────────────────────────────────────────

function renderParagraph(node: ParagraphNode): string {
  return `<p${styleAttr(blockAttrsToStyle(node.attrs))}>${renderInlineContent(node.content)}</p>`;
}

function renderHeading(node: HeadingNode): string {
  const tag = `h${node.attrs.level}`;
  return `<${tag}${styleAttr(blockAttrsToStyle(node.attrs))}>${renderInlineContent(node.content)}</${tag}>`;
}

function renderBlockquote(node: BlockquoteNode): string {
  return `<blockquote${styleAttr(blockAttrsToStyle(node.attrs))}>${renderBlockContent(node.content)}</blockquote>`;
}

function renderCodeBlock(node: CodeBlockNode): string {
  const text = (node.content ?? []).map((t) => t.text).join("");
  return `<pre><code${attr("data-language", node.attrs.language)}>${escapeText(text)}</code></pre>`;
}

function renderImage(node: ImageNode): string {
  let alignStyle: string | undefined;
  switch (node.attrs.align) {
    case "center":
      alignStyle = "display: block; margin: 0 auto";
      break;
    case "right":
      alignStyle = "display: block; margin-left: auto";
      break;
    case "full":
      alignStyle = "width: 100%";
      break;
  }

  const img = `<img${attr("src", node.attrs.src ?? undefined)}${attr(
    "alt",
    node.attrs.caption ?? "",
  )}${attr("width", node.attrs.width)}${attr("height", node.attrs.height)}${styleAttr(alignStyle)}>`;
  const caption = node.attrs.caption
    ? `<figcaption>${escapeText(node.attrs.caption)}</figcaption>`
    : "";
  return `<figure>${img}${caption}</figure>`;
}

function renderCallout(node: CalloutNode): string {
  const emoji = `<span data-type="emoji"><img${attr(
    "src",
    getEmojiUrl(node.attrs.emoji, "callout-icon"),
  )}${attr("alt", node.attrs.emoji)}></span>`;
  return `<div data-type="callout"${styleAttr(blockAttrsToStyle(node.attrs))}>${emoji}<div>${renderBlockContent(node.content)}</div></div>`;
}

// ── Lists ─────────────────────────────────────────────────────────────

function renderListItem(node: ListItemNode): string {
  return `<li>${renderBlockContent(node.content)}</li>`;
}

function renderTaskItem(node: TaskItemNode): string {
  const checked = node.attrs.checked ? " checked" : "";
  return `<li><input type="checkbox"${checked} disabled><div>${renderBlockContent(node.content)}</div></li>`;
}

function renderBulletList(node: BulletListNode): string {
  return `<ul>${(node.content ?? []).map(renderListItem).join("")}</ul>`;
}

function renderOrderedList(node: OrderedListNode): string {
  return `<ol${attr("start", node.attrs.start)}>${(node.content ?? []).map(renderListItem).join("")}</ol>`;
}

function renderTaskList(node: TaskListNode): string {
  return `<ul data-type="task-list">${(node.content ?? []).map(renderTaskItem).join("")}</ul>`;
}

// ── Tables ────────────────────────────────────────────────────────────

function buildColgroup(table: TableNode): string {
  const firstRow = table.content?.[0];
  if (!firstRow) return "";

  const widths: (number | undefined)[] = [];
  for (const cell of firstRow.content ?? []) {
    const span = cell.attrs?.colspan ?? 1;
    const cw = cell.attrs?.colwidth;
    if (cw && cw.length === span) widths.push(...cw);
    else for (let i = 0; i < span; i++) widths.push(undefined);
  }

  if (widths.every((w) => w === undefined)) return "";

  const cols = widths
    .map((w) => `<col${styleAttr(w ? `width: ${w}px` : undefined)}>`)
    .join("");
  return `<colgroup>${cols}</colgroup>`;
}

function renderTableCell(node: TableCellNode | TableHeaderNode): string {
  const tag = node.type === "tableHeader" ? "th" : "td";
  const style = node.attrs?.backgroundColor
    ? `background-color: ${node.attrs.backgroundColor}`
    : undefined;
  return `<${tag}${styleAttr(style)}${attr("colspan", node.attrs?.colspan)}${attr("rowspan", node.attrs?.rowspan)}>${renderBlockContent(node.content)}</${tag}>`;
}

function renderTableRow(node: TableRowNode): string {
  return `<tr>${(node.content ?? []).map(renderTableCell).join("")}</tr>`;
}

function renderTable(node: TableNode): string {
  return `<table>${buildColgroup(node)}<tbody>${(node.content ?? []).map(renderTableRow).join("")}</tbody></table>`;
}

// ── Dispatcher ────────────────────────────────────────────────────────

function renderBlock(node: BlockNode): string {
  switch (node.type) {
    case "paragraph":
      return renderParagraph(node);
    case "heading":
      return renderHeading(node);
    case "blockquote":
      return renderBlockquote(node);
    case "codeBlock":
      return renderCodeBlock(node);
    case "horizontalRule":
      return "<hr>";
    case "image":
      return renderImage(node);
    case "callout":
      return renderCallout(node);
    case "bulletList":
      return renderBulletList(node);
    case "orderedList":
      return renderOrderedList(node);
    case "taskList":
      return renderTaskList(node);
    case "table":
      return renderTable(node);
  }
}

function renderBlockContent(nodes?: BlockNode[]): string {
  return (nodes ?? []).map(renderBlock).join("");
}

// ── Entry point ───────────────────────────────────────────────────────

export function docToHTML(doc: DocContent): string {
  return doc.content.map(renderBlock).join("");
}

import type {
  DocContent,
  BlockNode,
  InlineNode,
  AnyMark,
  TextNode,
  ParagraphNode,
  HeadingNode,
  BlockquoteNode,
  CodeBlockNode,
  ImageNode,
  CalloutNode,
  BulletListNode,
  OrderedListNode,
  TaskListNode,
  TableNode,
  TableCellNode,
  TableHeaderNode,
} from "../jsonContent";

// ── Text helpers ──────────────────────────────────────────────────────

function hexIdToUnicode(hexId: string): string {
  return hexId
    .split("-")
    .map((cp) => String.fromCodePoint(parseInt(cp, 16)))
    .join("");
}

function escapeInline(text: string): string {
  return text.replace(/[\\`*_~\[\]<]/g, "\\$&");
}

function formatInlineCode(text: string): string {
  let maxRun = 0;
  let currentRun = 0;
  for (const ch of text) {
    if (ch === "`") {
      currentRun++;
      if (currentRun > maxRun) maxRun = currentRun;
    } else {
      currentRun = 0;
    }
  }
  const delim = "`".repeat(maxRun + 1);
  const padded = text.startsWith("`") || text.endsWith("`");
  return padded ? `${delim} ${text} ${delim}` : `${delim}${text}${delim}`;
}

function prefixLines(
  text: string,
  prefix: string,
  firstPrefix: string = prefix,
): string {
  return text
    .split("\n")
    .map((line, i) => {
      const p = i === 0 ? firstPrefix : prefix;
      return line === "" ? p.trimEnd() : p + line;
    })
    .join("\n");
}

// ── Marks ─────────────────────────────────────────────────────────────

function applyMark(content: string, mark: AnyMark): string {
  switch (mark.type) {
    case "bold":
      return `**${content}**`;
    case "italic":
      return `*${content}*`;
    case "strike":
      return `~~${content}~~`;
    case "underline":
      return `<u>${content}</u>`;
    case "link":
      return `[${content}](${mark.attrs.href})`;
    case "code":
      // Code marks are handled in renderTextNode (text inside is literal).
      // Reaching here shouldn't happen; emit conservatively.
      return formatInlineCode(content);
    case "textStyle":
      // No Markdown equivalent — strip styling, keep text.
      return content;
  }
}

function renderTextNode(node: TextNode): string {
  const marks = node.marks ?? [];
  const codeIdx = marks.findIndex((m) => m.type === "code");

  if (codeIdx === -1) {
    let content = escapeInline(node.text);
    for (const mark of marks) {
      content = applyMark(content, mark);
    }
    return content;
  }

  // Code mark present: text inside the code span is literal.
  // Marks before `code` cannot wrap literal text and are dropped.
  // Marks after `code` wrap the code span normally.
  let content = formatInlineCode(node.text);
  for (let i = codeIdx + 1; i < marks.length; i++) {
    content = applyMark(content, marks[i]);
  }
  return content;
}

// ── Inline rendering ──────────────────────────────────────────────────

function renderInline(node: InlineNode): string {
  switch (node.type) {
    case "text":
      return renderTextNode(node);
    case "hardBreak":
      return "\\\n";
    case "emoji":
      return hexIdToUnicode(node.attrs.hexId);
  }
}

function renderInlineContent(nodes?: InlineNode[]): string {
  return (nodes ?? []).map(renderInline).join("");
}

// ── Block rendering ───────────────────────────────────────────────────

function renderParagraph(node: ParagraphNode): string {
  return renderInlineContent(node.content);
}

function renderHeading(node: HeadingNode): string {
  return `${"#".repeat(node.attrs.level)} ${renderInlineContent(node.content)}`;
}

function renderBlockquote(node: BlockquoteNode): string {
  return prefixLines(renderBlockContent(node.content), "> ");
}

function renderCodeBlock(node: CodeBlockNode): string {
  const text = (node.content ?? []).map((t) => t.text).join("");
  let maxRun = 2;
  const matches = text.match(/`+/g);
  if (matches) {
    for (const m of matches) {
      if (m.length > maxRun) maxRun = m.length;
    }
  }
  const fence = "`".repeat(Math.max(3, maxRun + 1));
  const lang = node.attrs.language;
  const opener = lang ? `${fence}${lang}` : fence;
  return `${opener}\n${text}\n${fence}`;
}

function renderImage(node: ImageNode): string {
  const src = node.attrs.src ?? "";
  const alt = node.attrs.caption ?? "";
  return `![${escapeInline(alt)}](${src})`;
}

function renderCallout(node: CalloutNode): string {
  const emoji = hexIdToUnicode(node.attrs.emoji);
  const inner = renderBlockContent(node.content);
  const combined = inner ? `${emoji}\n\n${inner}` : emoji;
  return prefixLines(combined, "> ");
}

// ── Lists ─────────────────────────────────────────────────────────────

function renderBulletList(node: BulletListNode): string {
  return (node.content ?? [])
    .map((item) => prefixLines(renderBlockContent(item.content), "  ", "- "))
    .join("\n");
}

function renderOrderedList(node: OrderedListNode): string {
  const start = node.attrs.start ?? 1;
  return (node.content ?? [])
    .map((item, i) => {
      const marker = `${start + i}. `;
      const indent = " ".repeat(marker.length);
      return prefixLines(renderBlockContent(item.content), indent, marker);
    })
    .join("\n");
}

function renderTaskList(node: TaskListNode): string {
  return (node.content ?? [])
    .map((item) => {
      const marker = item.attrs.checked ? "- [x] " : "- [ ] ";
      return prefixLines(renderBlockContent(item.content), "  ", marker);
    })
    .join("\n");
}

// ── Tables ────────────────────────────────────────────────────────────

function renderTableCell(cell: TableCellNode | TableHeaderNode): string {
  const parts: string[] = [];
  for (const block of cell.content ?? []) {
    if (block.type === "paragraph") {
      parts.push(renderInlineContent(block.content));
    }
    // Non-paragraph blocks can't be expressed in a GFM cell; skipped.
  }
  return parts.join("<br>").replace(/\|/g, "\\|").replace(/\n/g, " ");
}

function renderTable(node: TableNode): string {
  const rows = node.content ?? [];
  if (rows.length === 0) return "";

  const headerCells = (rows[0].content ?? []).map(renderTableCell);
  const colCount = headerCells.length;
  if (colCount === 0) return "";

  const lines: string[] = [];
  lines.push(`| ${headerCells.join(" | ")} |`);
  lines.push(`| ${Array(colCount).fill("---").join(" | ")} |`);
  for (const row of rows.slice(1)) {
    const cells = (row.content ?? []).map(renderTableCell);
    while (cells.length < colCount) cells.push("");
    cells.length = colCount;
    lines.push(`| ${cells.join(" | ")} |`);
  }
  return lines.join("\n");
}

// ── Dispatcher ────────────────────────────────────────────────────────

function renderBlock(node: BlockNode): string {
  switch (node.type) {
    case "paragraph":
      return renderParagraph(node);
    case "heading":
      return renderHeading(node);
    case "blockquote":
      return renderBlockquote(node);
    case "codeBlock":
      return renderCodeBlock(node);
    case "horizontalRule":
      return "---";
    case "image":
      return renderImage(node);
    case "callout":
      return renderCallout(node);
    case "bulletList":
      return renderBulletList(node);
    case "orderedList":
      return renderOrderedList(node);
    case "taskList":
      return renderTaskList(node);
    case "table":
      return renderTable(node);
  }
}

function renderBlockContent(nodes?: BlockNode[]): string {
  return (nodes ?? []).map(renderBlock).join("\n\n");
}

// ── Entry ─────────────────────────────────────────────────────────────

export function docToMarkdown(doc: DocContent): string {
  return doc.content.map(renderBlock).join("\n\n") + "\n";
}

import { type ReactNode, type CSSProperties, Fragment, type JSX } from "react";
import type {
  DocContent,
  BlockNode,
  InlineNode,
  AnyMark,
  ParagraphNode,
  HeadingNode,
  BlockquoteNode,
  CodeBlockNode,
  ImageNode,
  CalloutNode,
  BulletListNode,
  OrderedListNode,
  TaskListNode,
  ListItemNode,
  TaskItemNode,
  TableNode,
  TableRowNode,
  TableCellNode,
  TableHeaderNode,
  BlockAttrs,
} from "../jsonContent";
import { getEmojiUrl } from "./utils";

// ── Helpers ───────────────────────────────────────────────────────────

function blockAttrsToStyle(attrs?: BlockAttrs): CSSProperties {
  if (!attrs) return {};
  return {
    backgroundColor: attrs.backgroundColor,
    color: attrs.textColor,
    fontSize: attrs.fontSize,
    fontFamily: attrs.fontFamily,
    textAlign: attrs.textAlign,
  };
}

// ── Mark renderer (wraps inline content) ──────────────────────────────

function applyMarks(
  content: ReactNode,
  marks: AnyMark[],
  key: string,
): ReactNode {
  return marks.reduce((node, mark, i) => {
    const markKey = `${key}-mark-${i}`;
    switch (mark.type) {
      case "bold":
        return <strong key={markKey}>{node}</strong>;
      case "italic":
        return <em key={markKey}>{node}</em>;
      case "strike":
        return <s key={markKey}>{node}</s>;
      case "underline":
        return <u key={markKey}>{node}</u>;
      case "code":
        return <code key={markKey}>{node}</code>;
      case "link":
        return (
          <a
            key={markKey}
            href={mark.attrs.href}
            target={mark.attrs.target}
            rel="noreferrer"
          >
            {node}
          </a>
        );
      case "textStyle": {
        const style: CSSProperties = {
          color: mark.attrs?.color ?? undefined,
          fontFamily: mark.attrs?.fontFamily ?? undefined,
          fontSize: mark.attrs?.fontSize ?? undefined,
        };
        return (
          <span key={markKey} style={style}>
            {node}
          </span>
        );
      }
      default:
        return node;
    }
  }, content);
}

// ── Inline node renderer ──────────────────────────────────────────────

function renderInline(node: InlineNode, key: string): ReactNode {
  switch (node.type) {
    case "text": {
      const text: ReactNode = node.text;
      return node.marks?.length ? (
        applyMarks(text, node.marks, key)
      ) : (
        <Fragment key={key}>{text}</Fragment>
      );
    }
    case "hardBreak":
      return <br key={key} />;
    case "emoji":
      return (
        <span key={key} data-type="emoji">
          <img
            src={getEmojiUrl(node.attrs.hexId, "inline")}
            alt={node.attrs.name}
          />
        </span>
      );
  }
}

function renderInlineContent(nodes?: InlineNode[]): ReactNode[] {
  return (nodes ?? []).map((n, i) => renderInline(n, String(i)));
}

// ── Block node renderers ──────────────────────────────────────────────

function renderParagraph(node: ParagraphNode, key: string): ReactNode {
  return (
    <p key={key} style={blockAttrsToStyle(node.attrs)}>
      {renderInlineContent(node.content)}
    </p>
  );
}

function renderHeading(node: HeadingNode, key: string): ReactNode {
  const Tag = `h${node.attrs.level}` as const;
  return (
    <Tag key={key} style={blockAttrsToStyle(node.attrs)}>
      {renderInlineContent(node.content)}
    </Tag>
  );
}

function renderBlockquote(node: BlockquoteNode, key: string): ReactNode {
  return (
    <blockquote key={key} style={blockAttrsToStyle(node.attrs)}>
      {renderBlockContent(node.content)}
    </blockquote>
  );
}

function renderCodeBlock(node: CodeBlockNode, key: string): ReactNode {
  return (
    <pre key={key}>
      <code data-language={node.attrs.language}>
        {(node.content ?? []).map((t) => t.text).join("")}
      </code>
    </pre>
  );
}

function renderImage(node: ImageNode, key: string): ReactNode {
  const alignStyle: CSSProperties =
    node.attrs.align === "center"
      ? { display: "block", margin: "0 auto" }
      : node.attrs.align === "right"
        ? { display: "block", marginLeft: "auto" }
        : node.attrs.align === "full"
          ? { width: "100%" }
          : {};

  return (
    <figure key={key}>
      <img
        src={node.attrs.src ?? undefined}
        alt={node.attrs.caption ?? ""}
        width={node.attrs.width}
        height={node.attrs.height}
        style={alignStyle}
      />
      {node.attrs.caption && <figcaption>{node.attrs.caption}</figcaption>}
    </figure>
  );
}

function renderCallout(node: CalloutNode, key: string): ReactNode {
  return (
    <div key={key} style={blockAttrsToStyle(node.attrs)} data-type="callout">
      <span data-type="emoji">
        <img
          src={getEmojiUrl(node.attrs.emoji, "callout-icon")}
          alt={node.attrs.emoji}
        />
      </span>
      <div>{renderBlockContent(node.content)}</div>
    </div>
  );
}

// ── List renderers ────────────────────────────────────────────────────

function renderListItem(node: ListItemNode, key: string): ReactNode {
  return <li key={key}>{renderBlockContent(node.content)}</li>;
}

function renderTaskItem(node: TaskItemNode, key: string): ReactNode {
  return (
    <li key={key}>
      <input
        type="checkbox"
        defaultChecked={node.attrs.checked}
        readOnly
        style={{ marginTop: 3 }}
      />
      <div>{renderBlockContent(node.content)}</div>
    </li>
  );
}

function renderBulletList(node: BulletListNode, key: string): ReactNode {
  return (
    <ul key={key}>
      {(node.content ?? []).map((item, i) => renderListItem(item, String(i)))}
    </ul>
  );
}

function renderOrderedList(node: OrderedListNode, key: string): ReactNode {
  return (
    <ol key={key} start={node.attrs.start}>
      {(node.content ?? []).map((item, i) => renderListItem(item, String(i)))}
    </ol>
  );
}

function renderTaskList(node: TaskListNode, key: string): ReactNode {
  return (
    <ul key={key} data-type="task-list">
      {(node.content ?? []).map((item, i) => renderTaskItem(item, String(i)))}
    </ul>
  );
}

// ── Table renderers ───────────────────────────────────────────────────

function renderTableCell(
  node: TableCellNode | TableHeaderNode,
  key: string,
): ReactNode {
  const Tag = node.type === "tableHeader" ? "th" : "td";
  const style: CSSProperties = {
    backgroundColor: node.attrs?.backgroundColor,
  };
  return (
    <Tag
      key={key}
      style={style}
      colSpan={node.attrs?.colspan}
      rowSpan={node.attrs?.rowspan}
    >
      {renderBlockContent(node.content)}
    </Tag>
  );
}

function renderTableRow(node: TableRowNode, key: string): ReactNode {
  return (
    <tr key={key}>
      {(node.content ?? []).map((cell, i) => renderTableCell(cell, String(i)))}
    </tr>
  );
}

function renderTable(node: TableNode, key: string): ReactNode {
  return (
    <table key={key}>
      <tbody>
        {(node.content ?? []).map((row, i) => renderTableRow(row, String(i)))}
      </tbody>
    </table>
  );
}

// ── Core block dispatcher ─────────────────────────────────────────────

function renderBlock(node: BlockNode, key: string): ReactNode {
  switch (node.type) {
    case "paragraph":
      return renderParagraph(node, key);
    case "heading":
      return renderHeading(node, key);
    case "blockquote":
      return renderBlockquote(node, key);
    case "codeBlock":
      return renderCodeBlock(node, key);
    case "horizontalRule":
      return <hr key={key} />;
    case "image":
      return renderImage(node, key);
    case "callout":
      return renderCallout(node, key);
    case "bulletList":
      return renderBulletList(node, key);
    case "orderedList":
      return renderOrderedList(node, key);
    case "taskList":
      return renderTaskList(node, key);
    case "table":
      return renderTable(node, key);
  }
}

function renderBlockContent(nodes?: BlockNode[]): ReactNode[] {
  return (nodes ?? []).map((n, i) => renderBlock(n, String(i)));
}

// ── Root component ────────────────────────────────────────────────────

interface DocRendererOptions {
  className: string;
  style: CSSProperties;
  Tag: keyof JSX.IntrinsicElements;
}

export function docToReact(
  doc: DocContent,
  { className, style, Tag = "div" }: Partial<DocRendererOptions> = {},
) {
  return (
    <Tag className={className} style={style}>
      {doc.content.map((node, i) => renderBlock(node, String(i)))}
    </Tag>
  );
}
